/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently supports email channel settings; designed to extend
 * to additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': send as events occur
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Master toggle for all email notifications */
  enabled: boolean;
  /** How often to deliver email notifications */
  frequency: EmailFrequency;
  /** Which notification categories the user wants to receive */
  subscribedCategories: NotificationType[];
}

/**
 * Full notification preferences for a user.
 */
export interface UserNotificationPreferences {
  userId: string;
  email: EmailPreferences;
  updatedAt: Date;
}

/**
 * Input for creating or updating notification preferences.
 * All fields optional — missing fields keep their current (or default) values.
 */
export interface UpdatePreferencesInput {
  email?: {
    enabled?: boolean;
    frequency?: EmailFrequency;
    subscribedCategories?: NotificationType[];
  };
}

/** All notification categories that exist in the system. */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'user-updated',
];

/** Default preferences: everything enabled, immediate delivery. */
export function getDefaultPreferences(userId: string): UserNotificationPreferences {
  return {
    userId,
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
    },
    updatedAt: new Date(),
  };
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for notification preferences with in-memory storage.
 * Users without explicit preferences get defaults (all enabled, immediate delivery).
 *
 * Used by NotificationService to check whether a notification should be sent.
 */

import { Logger } from '../utils/logger.js';
import type { NotificationType } from '../models/notification.js';
import type {
  UserNotificationPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import {
  getDefaultPreferences,
  ALL_NOTIFICATION_CATEGORIES,
} from '../models/user-preferences.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Get preferences for a user. Returns defaults if none have been set.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    return this.preferences.get(userId) ?? getDefaultPreferences(userId);
  }

  /**
   * Update preferences for a user. Merges with existing (or default) preferences.
   */
  updatePreferences(
    userId: string,
    input: UpdatePreferencesInput,
  ): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    const updated: UserNotificationPreferences = {
      userId,
      email: {
        enabled: input.email?.enabled ?? current.email.enabled,
        frequency: input.email?.frequency ?? current.email.frequency,
        subscribedCategories:
          input.email?.subscribedCategories ?? current.email.subscribedCategories,
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Reset preferences for a user back to defaults.
   */
  resetPreferences(userId: string): UserNotificationPreferences {
    this.preferences.delete(userId);
    this.logger.info(`Reset preferences for user ${userId}`);
    return getDefaultPreferences(userId);
  }

  /**
   * Check if a notification should be sent to a user on the email channel.
   * Returns true if:
   *  - Email is enabled
   *  - The notification category is in the user's subscribed list
   *  - Frequency is 'immediate' (digest frequencies are not yet delivered)
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.email.enabled) {
      return false;
    }

    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      return false;
    }

    // Only immediate notifications are sent now; digest support is future work
    if (prefs.email.frequency !== 'immediate') {
      return false;
    }

    return true;
  }

  /**
   * Check if a user has explicitly set preferences.
   */
  hasExplicitPreferences(userId: string): boolean {
    return this.preferences.has(userId);
  }

  /**
   * Get all notification categories available in the system.
   */
  getAvailableCategories(): NotificationType[] {
    return [...ALL_NOTIFICATION_CATEGORIES];
  }

  /** Clear all stored preferences (for testing). */
  clearAll(): void {
    this.preferences.clear();
  }
}

