export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private deliveryLog: NotificationResult[] = [];
  private notifications: NotificationPayload[] = [];
  private preferencesService: PreferencesService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Set the preferences service used to check user notification preferences.
   * When set, notifications are only sent if the user's preferences allow it.
   * When not set, all notifications are sent (backward compatible).
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
    this.logger.info('Preferences service registered');
  }

// Check user preferences before sending
if (this.preferencesService && params.channel === 'email') {
  const recipientId = params.recipientUserId ?? params.recipient;
  if (!this.preferencesService.shouldSendEmail(recipientId, params.type)) {
    this.logger.info(
      `Notification ${payload.id} suppressed by user preferences for ${recipientId}`,
    );
    const result: NotificationResult = {
      success: true,
      notificationId: payload.id,
      channel: params.channel,
      deliveredAt: new Date(),
    };
    this.deliveryLog.push(result);
    return result;
  }
}

this.notifications.push(payload);

const adapter = this.adapters.get(params.channel);

