+      const recipientId = params.recipientUserId ?? params.recipient;
+      if (!this.preferencesService.shouldSendEmail(recipientId, params.type)) {
+        this.logger.info(
+          `Notification ${payload.id} suppressed by user preferences for ${recipientId}`,
+        );
+        const result: NotificationResult = {
+          success: true,
+          notificationId: payload.id,
+          channel: params.channel,
+          deliveredAt: new Date(),
+        };
+        this.deliveryLog.push(result);
+        return result;
+      }
+    }
+
     this.notifications.push(payload);

