+import { describe, it, expect, beforeEach } from 'vitest';
+import { PreferencesService } from '../../src/services/preferences.service.js';
+import { EventBus } from '../../src/events/event-bus.js';
+import {
+  NotificationService,
+  resetNotificationIdCounter,
+} from '../../src/services/notification.service.js';
+import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';
+import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
+
+describe('PreferencesService', () => {
+  let service: PreferencesService;
+
+  beforeEach(() => {
+    service = new PreferencesService();
+  });
+
+  describe('getPreferences', () => {
+    it('should return default preferences for unknown user', () => {
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.email.enabled).toBe(true);
+      expect(prefs.email.frequency).toBe('immediate');
+      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
+    });
+
+    it('should return stored preferences for known user', () => {
+      service.updatePreferences('user-1', { email: { enabled: false } });
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.email.enabled).toBe(false);
+    });
+  });
+
+  describe('updatePreferences', () => {
+    it('should toggle email enabled', () => {
+      const prefs = service.updatePreferences('user-1', { email: { enabled: false } });
+      expect(prefs.email.enabled).toBe(false);
+      expect(prefs.email.frequency).toBe('immediate'); // unchanged
+    });
+
+    it('should update frequency', () => {
+      const prefs = service.updatePreferences('user-1', {
+        email: { frequency: 'daily-digest' },
+      });
+      expect(prefs.email.frequency).toBe('daily-digest');
+      expect(prefs.email.enabled).toBe(true); // unchanged
+    });
+
+    it('should update subscribed categories', () => {
+      const prefs = service.updatePreferences('user-1', {
+        email: { subscribedCategories: ['order-confirmation'] },
+      });
+      expect(prefs.email.subscribedCategories).toEqual(['order-confirmation']);
+    });
+
+    it('should merge partial updates with existing preferences', () => {
+      service.updatePreferences('user-1', {
+        email: { frequency: 'weekly-digest' },
+      });
+      const prefs = service.updatePreferences('user-1', {
+        email: { enabled: false },
+      });
+      expect(prefs.email.enabled).toBe(false);
+      expect(prefs.email.frequency).toBe('weekly-digest'); // preserved from earlier
+    });
+
+    it('should set updatedAt timestamp', () => {
+      const before = new Date();
+      const prefs = service.updatePreferences('user-1', { email: { enabled: false } });
+      expect(prefs.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
+    });
+  });
+
+  describe('resetPreferences', () => {
+    it('should restore defaults after reset', () => {
+      service.updatePreferences('user-1', { email: { enabled: false } });
+      const prefs = service.resetPreferences('user-1');
+      expect(prefs.email.enabled).toBe(true);
+      expect(prefs.email.frequency).toBe('immediate');
+    });
+
+    it('should remove explicit preferences', () => {
+      service.updatePreferences('user-1', { email: { enabled: false } });
+      service.resetPreferences('user-1');
+      expect(service.hasExplicitPreferences('user-1')).toBe(false);
+    });
+  });
+
+  describe('shouldSendEmail', () => {
+    it('should return true with default preferences', () => {
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
+    });
+
+    it('should return false when email is disabled', () => {
+      service.updatePreferences('user-1', { email: { enabled: false } });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+    });
+
+    it('should return false for unsubscribed category', () => {
+      service.updatePreferences('user-1', {
+        email: { subscribedCategories: ['welcome'] },
+      });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
+    });
+
+    it('should return false for non-immediate frequency', () => {
+      service.updatePreferences('user-1', { email: { frequency: 'daily-digest' } });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+    });
+  });
+
+  describe('hasExplicitPreferences', () => {
+    it('should return false for unknown user', () => {
+      expect(service.hasExplicitPreferences('user-1')).toBe(false);
+    });
+
+    it('should return true after update', () => {
+      service.updatePreferences('user-1', { email: { enabled: true } });
+      expect(service.hasExplicitPreferences('user-1')).toBe(true);
+    });
+  });
+
+  describe('getAvailableCategories', () => {
+    it('should return all notification categories', () => {
+      expect(service.getAvailableCategories()).toEqual(ALL_NOTIFICATION_CATEGORIES);
+    });
+
+    it('should return a copy, not a reference', () => {
+      const cats = service.getAvailableCategories();
+      cats.push('order-confirmation');
+      expect(service.getAvailableCategories()).toEqual(ALL_NOTIFICATION_CATEGORIES);
+    });
+  });
+
+  describe('clearAll', () => {
+    it('should remove all stored preferences', () => {
+      service.updatePreferences('user-1', { email: { enabled: false } });
+      service.updatePreferences('user-2', { email: { enabled: false } });
+      service.clearAll();
+      expect(service.hasExplicitPreferences('user-1')).toBe(false);
+      expect(service.hasExplicitPreferences('user-2')).toBe(false);
+    });
+  });
+});
+
+describe('NotificationService with preferences', () => {
+  let eventBus: EventBus;
+  let notificationService: NotificationService;
+  let preferencesService: PreferencesService;
+
+  const makeUser = (id: string, email: string) => ({
+    id,
+    name: 'Test User',
+    email,
+    role: 'member' as const,
+    createdAt: new Date(),
+    updatedAt: new Date(),
+  });
+
+  const makeOrderCreatedEvent = (userId: string, email: string): OrderCreatedEvent => ({
+    type: 'order:created',
+    order: {
+      id: 'order-1',
+      userId,
+      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
+      total: 10,
+      status: 'pending',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    user: makeUser(userId, email),
+    timestamp: new Date(),
+  });
+
+  const makeUserCreatedEvent = (userId: string, email: string): UserCreatedEvent => ({
+    type: 'user:created',
+    user: makeUser(userId, email),
+    timestamp: new Date(),
+  });
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    notificationService = new NotificationService(eventBus);
+    preferencesService = new PreferencesService();
+    notificationService.setPreferencesService(preferencesService);
+    resetNotificationIdCounter();
